where 1=1
and r.risk_level=#{s.riskLevel}
and a.status=#{s.status}
and a.service_type=#{s.serviceType}

    and (
        r.assessment_no like concat('%',#{s.keyword},'%')
        or a.application_no like concat('%',#{s.keyword},'%')
        or o.order_no like concat('%',#{s.keyword},'%')
        or o.product_name like concat('%',#{s.keyword},'%')
        or r.risk_tags like concat('%',#{s.keyword},'%')
        or r.risk_reasons like concat('%',#{s.keyword},'%')
    )

