    assessment_no, application_id, risk_level, risk_score, risk_tags,
    risk_reasons, suggested_action, rule_detail_json, ai_summary,
    ai_status, ai_error_message
)
values(
    #{assessmentNo}, #{applicationId}, #{riskLevel}, #{riskScore}, #{riskTags},
    #{riskReasons}, #{suggestedAction}, #{ruleDetailJson}, #{aiSummary},
    #{aiStatus}, #{aiErrorMessage}
)
